def calculate_porter_measure(word: str) -> int:
    """Calculates Porter's measure m for a word, representing VC repetitions."""
    # Determine vowel/consonant flags
    vowels = 'aeiou'
    is_vowel = []
    for i, char in enumerate(word):
        if char in vowels:
            is_vowel.append(True)
        elif char == 'y' and i > 0 and not is_vowel[i-1]:
            is_vowel.append(True)
        else:
            is_vowel.append(False)

    # Convert flags to states: V (True) or C (False)
    # Compress consecutive identical flags
    states = []
    for val in is_vowel:
        if not states or states[-1] != val:
            states.append(val)

    # Count 'VC' transitions
    m = 0
    state_str = ''.join(['V' if s else 'C' for s in states])
    # Find patterns of 'VC'
    idx = 0
    while True:
        pos = state_str.find('VC', idx)
        if pos != -1:
            m += 1
            idx = pos + 2
        else:
            break
    return m

def run_practice():
    assert calculate_porter_measure('tree') == 0 # C V (no VC transition)
    assert calculate_porter_measure('troubles') == 2 # C V C V C (VC transitions: ou->bl, e->s)
    print('[PASS] Porter measure m calculations verified successfully.')

if __name__ == '__main__':
    run_practice()
